SELECT COUNT(*) OVER() TOTAL , c.SCH_INSTC_ID , c.SCH_ID , c.JOB_STS_CD , d.CD_NM AS JOB_STS_NM , c.JOB_PRG_RT || '%' JOB_PRG_RT , TO_CHAR(c.JOB_FR_DATE,'YYYY.MM.DD HH24:MI') JOB_FR_DATE , TO_CHAR(c.JOB_TO_DATE,'YYYY.MM.DD HH24:MI') JOB_TO_DATE , c.JOB_STS_MSG , c.JOB_SVR_NM , c.JOB_SVR_IP , c.IMMD_EXE_YN , c.IMMD_EXE_USER_ID , (SELECT NVL(MAX(f.USER_NM),'manual') FROM AD_USER_MST f WHERE f.USER_ID = c.IMMD_EXE_USER_ID) IMMD_EXE_USER_NM FROM BA_SCH_MST b, BA_SCH_EXE_DTS c, (SELECT * FROM AD_COMM_CD WHERE COMM_GRP_CD = 'JOB_STS_CD') d WHERE 1=1 AND b.SCH_ID = c.SCH_ID AND c.JOB_STS_CD = d.COMM_CD AND b.SCH_ID = #{schId} ORDER BY c.JOB_FR_DATE DESC
#{endRow}
#{startRow}
